import React, { useEffect, useState } from "react";
import axios from "axios";
import { useTheme } from "../context/ThemeContext";

const Dashboard = () => {
  const [summary, setSummary] = useState({
    totalIncome: 0,
    totalExpenses: 0,
    balance: 0,
  });

  const { darkMode, setDarkMode } = useTheme();

  useEffect(() => {
    const fetchSummary = async () => {
      try {
        const token = localStorage.getItem("token");

        const res = await axios.get(
          "http://localhost:5000/api/dashboard/summary",
          {
            headers: { Authorization: `Bearer ${token}` },
          }
        );

        setSummary(res.data);
      } catch (err) {
        console.error(err);
      }
    };

    fetchSummary();
  }, []);

  return (
    <div className="min-h-screen p-8 bg-gray-100 dark:bg-slate-900 transition-colors duration-300">
      
      <div className="navbar rounded-xl mb-8">
        <h1 className="text-3xl font-bold">Finora AI Dashboard</h1>

        <button
          onClick={() => setDarkMode(!darkMode)}
          className="px-4 py-2 rounded-lg bg-blue-600 text-white"
        >
          {darkMode ? "Light Mode" : "Dark Mode"}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="card bg-green-500 text-white">
          <h2 className="text-lg font-semibold">Total Income</h2>
          <p className="text-3xl font-bold">₹{summary.totalIncome}</p>
        </div>

        <div className="card bg-red-500 text-white">
          <h2 className="text-lg font-semibold">Total Expenses</h2>
          <p className="text-3xl font-bold">₹{summary.totalExpenses}</p>
        </div>

        <div className="card bg-blue-700 text-white">
          <h2 className="text-lg font-semibold">Balance</h2>
          <p className="text-3xl font-bold">₹{summary.balance}</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
